import React, { useState } from "react";
import { fn, userEvent, within, expect } from "@storybook/test";

import { Box } from "../Box";
import { Button } from "../Button";
import { Input } from "../Input";
import { Popover } from "./Popover";
import { Stack, HStack } from "../Stack";
import { Text } from "../Text";

export default {
  title: "Overlay/Popover",
  component: Popover,
  tags: ["autodocs"],
  parameters: {
    layout: "padded",
    docs: {
      description: {
        component:
          "Popover component for displaying floating content relative to a trigger element.",
      },
    },
  },
  args: {
    onOpenChange: fn(),
  },
  argTypes: {
    size: {
      control: "select",
      options: ["xs", "sm", "md", "lg"],
      description: "Size of the popover",
    },
    onOpenChange: {
      action: "open changed",
      description: "Callback when popover open state changes",
    },
  },
};

export const Default = {
  args: {
    size: "md",
  },
  render: (args) => (
    <Popover {...args}>
      <Popover.Trigger>
        <Button variant="outline">Open Popover</Button>
      </Popover.Trigger>
      <Popover.Content>
        <Popover.Arrow />
        <Popover.Body>
          <Popover.Title fontWeight="medium">Popover Title</Popover.Title>
          <Text mt={2}>This is the popover content. You can put any content here.</Text>
        </Popover.Body>
      </Popover.Content>
    </Popover>
  ),
  play: async ({ canvasElement, args }) => {
    const canvas = within(canvasElement);
    const openButton = canvas.getByRole("button", { name: /open popover/i });

    // Click to open popover
    await userEvent.click(openButton);
    await expect(args.onOpenChange).toHaveBeenCalled();
  },
};

